  1110→		Name:      gateway,
  1111→	}
  1112→	res := make([]*config.Config, 0, len(ps.virtualServiceIndex.privateByNamespaceAndGateway[name])+
  1113→		len(ps.virtualServiceIndex.exportedToNamespaceByGateway[name])+
  1114→		len(ps.virtualServiceIndex.publicByGateway[gateway]))
  1115→	// Use index-based iteration to get stable pointers to slice elements
