  1123→	// We do 2 iterations here to avoid extra allocations.
  1124→	for i := range ps.virtualServiceIndex.publicByGateway[gateway] {
  1125→		vs := &ps.virtualServiceIndex.publicByGateway[gateway][i]
  1126→		if UseGatewaySemantics(*vs) && vs.Namespace == proxyNamespace {
